mapper.select:
${pagingTop} SELECT HOMEPAGE_ID, TEACHER_IDX, TEACHER_ID, MEMBER_KEY, TEACHER_NAME, TEACHER_SUBJECT_NAME, STAGE, TEACHER_BIRTH, TEACHER_SEX, TEACHER_PHONE, TEACHER_CELL_PHONE, TEACHER_NATIONALITY, TEACHER_ZIPCODE, TEACHER_ADDRESS, TEACHER_HISTORY, TEACHER_HISTORY_MANAGE, SELF_INFO_YN, TO_CHAR(ADD_DATE, 'yyyy-mm-dd') AS ADD_DATE, CONFIRM_YN, FILE_NAME, REAL_FILE_NAME, FILE_EXTENSION, FILE_SIZE, teacher_location_code, getCodeIdToCodeName('CMS', 'C0021', teacher_location_code) AS teacher_location_code_name, subject_cd, getCodeIdToCodeName('CMS', 'C0023', subject_cd) AS subject_cd_name, teacher_email, teacher_education, teacher_experience, teacher_certifications, teacher_open_files,TEACHER_TEXT_AREA FROM TEACHER_REQ_MANAGE WHERE HOMEPAGE_ID = #{homepage_id} AND DELETE_YN = 'N'
AND ${search_type} LIKE '%'||#{search_text}||'%'
AND CONFIRM_YN = #{confirm_yn}
AND subject_cd LIKE #{largeSubjectCode} || '%'
AND subject_cd = #{smallSubjectCode}
AND teacher_location_code = #{teacher_location_code}
ORDER BY TEACHER_IDX DESC ${pagingBottom}

SELECT COUNT(*) FROM TEACHER_REQ_MANAGE WHERE HOMEPAGE_ID = #{homepage_id} AND DELETE_YN = 'N'
AND ${search_type} LIKE '%'||#{search_text}||'%'
AND CONFIRM_YN = #{confirm_yn}
AND subject_cd LIKE #{largeSubjectCode} || '%'
AND subject_cd = #{smallSubjectCode}
AND teacher_location_code = #{teacher_location_code}
ORDER BY TEACHER_IDX DESC

mapper.update:
UPDATE 
	TEACHER_REQ_MANAGE
SET
	CONFIRM_YN = #{confirm_yn}
WHERE
	HOMEPAGE_ID = #{homepage_id} AND TEACHER_IDX = #{teacher_idx}

UPDATE TEACHER
SET TEACHER_HISTORY_MANAGE = #{teacher_history_manage}
WHERE HOMEPAGE_ID = #{homepage_id} AND TEACHER_IDX = #{teacher_idx}
